let questions = [],
  curri = 0,
  score = 0,
  answered = !1;
function initQuiz() {
  ((questions = shuffle([...ALL_QUESTIONS]).slice(0, 10)),
    (curri = 0),
    (score = 0),
    (answered = !1),
    (document.getElementById("q-total").textContent = questions.length),
    (document.getElementById("final-total").textContent = questions.length),
    (document.getElementById("quiz-screen").style.display = "block"),
    (document.getElementById("result-screen").style.display = "none"),
    renderQuestion());
}
function renderQuestion() {
  const e = questions[curri];
  ((answered = !1),
    (document.getElementById("q-num").textContent = curri + 1),
    (document.getElementById("score-now").textContent = score));
  const t = (curri / questions.length) * 100;
  ((document.getElementById("progress-fill").style.width = t + "%"),
    (document.getElementById("q-category").textContent = e.category),
    (document.getElementById("q-text").textContent = e.text));
  const n = document.getElementById("question-card");
  ((n.style.animation = "none"),
    n.offsetWidth,
    (n.style.animation = "slideIn 0.4s ease"));
  const o = document.getElementById("answers-grid");
  o.innerHTML = "";
  shuffleIndexes(e.answers.length).forEach((t) => {
    const n = document.createElement("button");
    ((n.className = "answer-btn"),
      (n.textContent = e.answers[t]),
      (n.dataset.index = t),
      n.addEventListener("click", () => handleAnswer(n, t, e.correct, e.hint)),
      o.appendChild(n));
  });
  const s = document.getElementById("feedback");
  ((s.style.display = "none"),
    (s.className = ""),
    (document.getElementById("next-btn").style.display = "none"));
}
function handleAnswer(e, t, n, o) {
  if (answered) return;
  answered = !0;
  const s = document.querySelectorAll(".answer-btn");
  s.forEach((e) => (e.disabled = !0));
  (t === n
    ? (e.classList.add("correct"), score++, showFeedback(!0, o))
    : (e.classList.add("wrong"),
      s.forEach((e) => {
        parseInt(e.dataset.index) === n && e.classList.add("show-correct");
      }),
      showFeedback(!1, o)),
    (document.getElementById("score-now").textContent = score));
  const r = document.getElementById("next-btn");
  ((r.style.display = "block"),
    (r.textContent =
      curri + 1 < questions.length
        ? "Следующий вопрос →"
        : "Посмотреть результат 🎉"),
    (r.onclick = nextQuestion));
}
function showFeedback(e, t) {
  const n = document.getElementById("feedback");
  ((n.style.display = "block"),
    (n.className = e ? "correct" : "wrong"),
    (document.getElementById("feedback-icon").textContent = e ? "✅ " : "❌ "),
    (document.getElementById("feedback-text").textContent = e
      ? "Правильно! Отличная работа!"
      : "Неправильно. Не расстраивайся!"),
    (document.getElementById("feedback-hint").textContent = "💡 " + t));
}
function nextQuestion() {
  (curri++, curri < questions.length ? renderQuestion() : showResult());
}
function showResult() {
  document.getElementById("quiz-screen").style.display = "none";
  document.getElementById("result-screen").style.display = "block";
  const e = questions.length,
    t = score / e;
  let n, o, s, r;
  ((document.getElementById("final-score").textContent = score),
    (document.getElementById("progress-fill").style.width = "100%"),
    t >= 0.9
      ? ((n = "🏆"),
        (o = "Супергерой безопасности!"),
        (s = "⭐⭐⭐"),
        (r = `Ты настоящий эксперт по кибербезопасности! ${score} из ${e} — невероятный результат. Ты точно защитишь себя в интернете!`))
      : t >= 0.7
        ? ((n = "😎"),
          (o = "Очень хорошо!"),
          (s = "⭐⭐"),
          (r = `${score} из ${e} — отличный результат! Ты многое знаешь о безопасности. Повтори пропущенные темы и станешь настоящим экспертом!`))
        : t >= 0.5
          ? ((n = "🙂"),
            (o = "Неплохо!"),
            (s = "⭐"),
            (r = `${score} из ${e} — хорошее начало! Почитай наши материалы о кибербезопасности и попробуй ещё раз.`))
          : ((n = "💪"),
            (o = "Учиться никогда не поздно!"),
            (s = "🌱"),
            (r = `${score} из ${e}. Не расстраивайся — загляни в раздел «Для детей» и узнай больше о безопасности в интернете. Потом попробуй снова!`)),
    (document.getElementById("result-emoji").textContent = n),
    (document.getElementById("result-title").textContent = o),
    (document.getElementById("result-stars").textContent = s),
    (document.getElementById("result-msg").textContent = r));
}
function restartQuiz() {
  initQuiz();
}
function shuffle(e) {
  for (let t = e.length - 1; t > 0; t--) {
    const n = Math.floor(Math.random() * (t + 1));
    [e[t], e[n]] = [e[n], e[t]];
  }
  return e;
}
function shuffleIndexes(e) {
  return shuffle(Array.from({ length: e }, (e, t) => t));
}
((window.restartQuiz = restartQuiz),
  document.addEventListener("DOMContentLoaded", initQuiz));
